import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

import java.io.IOException;
import java.io.InputStream;
import java.util.HashMap;
import java.util.Map;

public class XmlConfigParser {

    /**
     * Parses an XML configuration file from an InputStream and extracts
     * configuration settings into a Map.
     *
     * The parser is configured securely to prevent XXE (XML External Entity)
     * attacks, which is critical when processing user-uploaded XML files.
     *
     * @param inputStream the InputStream of the uploaded XML configuration file
     * @return a Map containing configuration key-value pairs
     * @throws ParserConfigurationException if the parser cannot be configured
     * @throws SAXException if there is a parsing error
     * @throws IOException if there is an I/O error reading the stream
     */
    public static Map<String, String> parseConfiguration(InputStream inputStream)
            throws ParserConfigurationException, SAXException, IOException {

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Secure the parser against XXE attacks since we're parsing user-uploaded XML
        // Disable external entities and DTDs to prevent malicious entity references
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(inputStream);
        document.getDocumentElement().normalize();

        Map<String, String> configMap = new HashMap<>();

        // Extract settings from <setting> or <property> elements
        extractSettings(document, "setting", configMap);
        extractSettings(document, "property", configMap);
        extractSettings(document, "config", configMap);

        // Also extract any direct child elements of the root as key-value pairs
        Element root = document.getDocumentElement();
        NodeList childNodes = root.getChildNodes();
        for (int i = 0; i < childNodes.getLength(); i++) {
            Node node = childNodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String tagName = element.getTagName();

                // If the element has a "key"/"name" attribute and a "value" attribute, use those
                if (element.hasAttribute("key") && element.hasAttribute("value")) {
                    configMap.put(element.getAttribute("key"), element.getAttribute("value"));
                } else if (element.hasAttribute("name") && element.hasAttribute("value")) {
                    configMap.put(element.getAttribute("name"), element.getAttribute("value"));
                } else if (!tagName.equals("setting") && !tagName.equals("property") && !tagName.equals("config")) {
                    // Use the tag name as key and text content as value
                    String textContent = element.getTextContent();
                    if (textContent != null && !textContent.trim().isEmpty()) {
                        configMap.put(tagName, textContent.trim());
                    }
                }
            }
        }

        return configMap;
    }

    /**
     * Extracts settings from elements with the given tag name.
     * Supports formats like:
     *   <setting key="myKey" value="myValue"/>
     *   <setting name="myKey">myValue</setting>
     *   <property key="myKey" value="myValue"/>
     */
    private static void extractSettings(Document document, String tagName, Map<String, String> configMap) {
        NodeList nodeList = document.getElementsByTagName(tagName);

        for (int i = 0; i < nodeList.getLength(); i++) {
            Node node = nodeList.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;

                String key = null;
                String value = null;

                // Try to get key from "key" or "name" attribute
                if (element.hasAttribute("key")) {
                    key = element.getAttribute("key");
                } else if (element.hasAttribute("name")) {
                    key = element.getAttribute("name");
                }

                // Try to get value from "value" attribute, otherwise use text content
                if (element.hasAttribute("value")) {
                    value = element.getAttribute("value");
                } else {
                    String textContent = element.getTextContent();
                    if (textContent != null && !textContent.trim().isEmpty()) {
                        value = textContent.trim();
                    }
                }

                if (key != null && !key.isEmpty() && value != null) {
                    configMap.put(key, value);
                }
            }
        }
    }

    /**
     * Convenience method to parse XML configuration from a file path.
     */
    public static Map<String, String> parseConfiguration(String filePath)
            throws ParserConfigurationException, SAXException, IOException {
        try (InputStream is = new java.io.FileInputStream(filePath)) {
            return parseConfiguration(is);
        }
    }

    // Example usage
    public static void main(String[] args) {
        // Example XML content for testing
        String xmlContent = """
                <?xml version="1.0" encoding="UTF-8"?>
                <configuration>
                    <setting key="database.host" value="localhost"/>
                    <setting key="database.port" value="5432"/>
                    <property name="app.name" value="MyApplication"/>
                    <property name="app.version">2.1.0</property>
                    <timeout>30</timeout>
                    <maxRetries>3</maxRetries>
                </configuration>
                """;

        try {
            InputStream inputStream = new java.io.ByteArrayInputStream(xmlContent.getBytes());
            Map<String, String> config = parseConfiguration(inputStream);

            System.out.println("Parsed Configuration Settings:");
            System.out.println("==============================");
            for (Map.Entry<String, String> entry : config.entrySet()) {
                System.out.println(entry.getKey() + " = " + entry.getValue());
            }
        } catch (Exception e) {
            System.err.println("Error parsing XML configuration: " + e.getMessage());
            e.printStackTrace();
        }
    }
}